import{_ as e,c as n,o as s,d as o}from"./app.6040d904.js";var t="/laravuel-apispa/assets/create-collection.1b166129.jpg",p="/laravuel-apispa/assets/gear.b2e3c44f.jpg",c="/laravuel-apispa/assets/surprise1.03a6c491.jpg",r="/laravuel-apispa/assets/surprise2.2cb245f1.jpg",i="/laravuel-apispa/assets/pre-request.15b43282.jpg",l="/laravuel-apispa/assets/csrf-cookie.8e29896e.jpg",u="/laravuel-apispa/assets/xxsrftoken.8dddacb6.jpg",d="/laravuel-apispa/assets/unauthenticated.49ff81dc.jpg",m="/laravuel-apispa/assets/cookies.873e1bf1.jpg",a="/laravuel-apispa/assets/localhostport.5546c2aa.jpg",k="/laravuel-apispa/assets/envname.3879e481.jpg",g="/laravuel-apispa/assets/logout.9fc59a41.jpg";const A='{"title":"Laravel Sanctum (Airlock) con Postman","description":"","frontmatter":{},"headers":[{"level":2,"title":"La esencia de esto","slug":"la-esencia-de-esto"},{"level":2,"title":"Crear una Colecci\xF3n de Postman","slug":"crear-una-coleccion-de-postman"},{"level":2,"title":"Crea un ambiente","slug":"crea-un-ambiente"},{"level":2,"title":"Agregar un script de solicitud previa","slug":"agregar-un-script-de-solicitud-previa"},{"level":2,"title":"Hacer solicitudes autenticadas","slug":"hacer-solicitudes-autenticadas"},{"level":2,"title":"Una nota r\xE1pida sobre otras rutas web","slug":"una-nota-rapida-sobre-otras-rutas-web"}],"relativePath":"laravel/laravel-with-postman.md"}',v={},h=o('<h1 id="laravel-sanctum-airlock-con-postman" tabindex="-1">Laravel Sanctum (Airlock) con Postman <a class="header-anchor" href="#laravel-sanctum-airlock-con-postman" aria-hidden="true">#</a></h1><div class="info custom-block"><p class="custom-block-title">Prueba</p><p>Esta lecci\xF3n en <a href="https://blog.codecourse.com/laravel-sanctum-airlock-with-postman/" target="_blank" rel="noopener noreferrer">idioma original</a></p></div><p>Recuerda que est\xE1s usando Laravel como una API. Y para probarlo con Postman, esto requiere un poco m\xE1s de trabajo que simplemente adjuntar un token (a menos que est\xE9 utilizando autenticaci\xF3n basada en token con Sanctum).</p><p>Si est\xE1 creando un SPA y quiere probar sus terminales con autenticaci\xF3n basada en cookies en Postman, aqu\xED le mostramos c\xF3mo hacerlo.</p><h2 id="la-esencia-de-esto" tabindex="-1">La esencia de esto <a class="header-anchor" href="#la-esencia-de-esto" aria-hidden="true">#</a></h2><p>Debido a que Sanctum utiliza la autenticaci\xF3n basada en cookies y llega a puntos finales protegidos por CSRF como <code>/login</code> y <code>/logout</code>, debemos asegurarnos de que estamos enviando un token CSRF con Postman. Obtenemos esto enviando una solicitud a <code>/sanctum/csrf-cookie</code> primero. Tambi\xE9n tendremos que asegurarnos de que el <code>Referrer</code> se env\xEDe correctamente para futuras solicitudes de Sanctum para permitirlos.</p><p>Estamos probando esto con un <a href="./../laravel/setup-laravel-api.html">Proyecto Laravel correctamente configurado con Sanctum</a>, que permite solicitudes de localhost, en t\xE9rminos de dominios CORS y Sanctum.</p><h2 id="crear-una-coleccion-de-postman" tabindex="-1">Crear una Colecci\xF3n de Postman <a class="header-anchor" href="#crear-una-coleccion-de-postman" aria-hidden="true">#</a></h2><p>Recomendamos crear una colecci\xF3n de Postman para que podamos aplicar nuestro script de solicitud previa (en un momento) a todos los puntos finales.</p><p><img src="'+t+'" alt="Create collection"></p><p>Una vez que se crea la colecci\xF3n, esto facilita la aplicaci\xF3n de un script de solicitud previa a todos los puntos finales de esa colecci\xF3n. Tambi\xE9n ayuda a mantener todo limpio y ordenado.</p><h2 id="crea-un-ambiente" tabindex="-1">Crea un ambiente <a class="header-anchor" href="#crea-un-ambiente" aria-hidden="true">#</a></h2><p>Vamos a configurar un token CSRF en nuestras variables de entorno en Postman, por lo que debemos crear un entorno de Postman.</p><p>Haga clic en la rueda dentada en la parte superior derecha de Postman, haga clic en Agregar y asigne un nombre a su entorno (el m\xEDo <code>Api-test</code>). Haga clic en Agregar nuevamente y cambie a su entorno en la parte superior derecha (vea la parte superior derecha de la captura de pantalla).</p><p><img src="'+p+'" alt="login"></p><h2 id="agregar-un-script-de-solicitud-previa" tabindex="-1">Agregar un script de solicitud previa <a class="header-anchor" href="#agregar-un-script-de-solicitud-previa" aria-hidden="true">#</a></h2><p>Antes de realizar alguna solicitud, cree una nueva solicitud para <code>/login</code> en Postman, gu\xE1rdela en su colecci\xF3n y agregue los datos del formulario (email y password).</p><p><img src="'+c+'" alt="login"></p><p>Pero, antes agregue un encabezado <code>Accept</code> con <code>application/json</code> tambi\xE9n, para recuperar JSON.</p><p><img src="'+r+'" alt="login"></p><p>No es de extra\xF1ar aqu\xED, recibimos un error de discrepancia de token CSRF.</p><p>Entonces, agreguemos ese <code>Pre-request Scripts</code> para tomar el token CSRF usando Sanctum, configurando el valor en nuestras variables de entorno de Postman.</p><p>Edite su colecci\xF3n y cambie a la pesta\xF1a <code>Pre-request Scripts</code> y agregue lo siguiente.</p><p><img src="'+i+`" alt="Pre request"></p><p>No lo escriba desde la captura de pantalla, c\xF3pielo desde aqu\xED:</p><div class="language-js"><pre><code>pm<span class="token punctuation">.</span><span class="token function">sendRequest</span><span class="token punctuation">(</span><span class="token punctuation">{</span>
    <span class="token literal-property property">url</span><span class="token operator">:</span> <span class="token string">&#39;http://localhost:8000/sanctum/csrf-cookie&#39;</span><span class="token punctuation">,</span>
    <span class="token literal-property property">method</span><span class="token operator">:</span> <span class="token string">&#39;GET&#39;</span>
<span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token parameter">error<span class="token punctuation">,</span> response<span class="token punctuation">,</span> <span class="token punctuation">{</span> cookies <span class="token punctuation">}</span></span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token operator">!</span>error<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        pm<span class="token punctuation">.</span>environment<span class="token punctuation">.</span><span class="token function">set</span><span class="token punctuation">(</span><span class="token string">&#39;xsrf-token&#39;</span><span class="token punctuation">,</span> cookies<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token string">&#39;XSRF-TOKEN&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
</code></pre></div><p>Haz click en <code>Save</code> y eso se guardar\xE1.</p><p>Ahora haga otra solicitud a <code>/login</code>. Esta vez, se ejecutar\xE1 <code>Pre-request Scripts</code> y establecer\xE1 la cookie que obtenemos del punto final <code>/sanctum/csrf-cookie</code> en nuestro entorno.</p><p>Presiona el \xEDcono del ojo en la parte superior derecha para verificar.</p><p><img src="`+l+'" alt="Csrf cookie"></p><p>Genial, ese es nuestro valor de token CSRF.</p><p>Ahora actualice la solicitud <code>/login</code> para agregar el encabezado <code>X-XSRF-TOKEN</code> con el valor:</p><p><strong>{ { xsrf - token } }</strong></p><p>(este es el valor de nuestra variable de entorno) y env\xEDe la solicitud nuevamente.</p><p><img src="'+u+'" alt="X xsrf token"></p><p>Aseg\xFArese de no incluir espacios entre las llaves (por ejemplo, <strong>{ { xsrf - token } }</strong>). A Postman no le gusta eso.</p><p>Espero que eso haya funcionado para ti. De lo contrario, es posible que deba verificar la configuraci\xF3n de Sanctum.</p><h2 id="hacer-solicitudes-autenticadas" tabindex="-1">Hacer solicitudes autenticadas <a class="header-anchor" href="#hacer-solicitudes-autenticadas" aria-hidden="true">#</a></h2><p>As\xED que hemos ordenado CSRF, ahora haremos una solicitud a <code>/api/users</code> para verificar que realmente estamos autenticados. Cree una solicitud para esto en Postman y agr\xE9guelo a su colecci\xF3n. Y por supuesto, enviar esa solicitud.</p><p><img src="'+d+'" alt="Unauthenticated"></p><p>Hmm, no autenticado.</p><p>Ahora, esto deber\xEDa funcionar. Postman ha almacenado las cookies que obtuvimos al realizar la solicitud anterior a <code>/login</code> y las enviar\xE1 junto con esta solicitud. Puede verificar esto haciendo click en el enlace de cookies en la parte superior derecha de su solicitud.</p><p><img src="'+m+`" alt="Cookies"></p><p>La raz\xF3n por la que esto no funciona es que Sanctum est\xE1 denegando la solicitud autenticada en funci\xF3n al <code>Referrer</code>.</p><p>Si est\xE1 interesado en sumergirse en alg\xFAn c\xF3digo de Sanctum y averiguar por qu\xE9, abra el middleware de <code>GuaranteeFrontendRequestsAreStateful</code> y compruebe el m\xE9todo <code>fromFrontend</code> por el que se canalizan todas las solicitudes.</p><div class="language-php"><pre><code><span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">function</span> <span class="token function-definition function">fromFrontend</span><span class="token punctuation">(</span><span class="token variable">$request</span><span class="token punctuation">)</span>
<span class="token punctuation">{</span>
    <span class="token variable">$referer</span> <span class="token operator">=</span> <span class="token class-name static-context">Str</span><span class="token operator">::</span><span class="token function">replaceFirst</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;https://&#39;</span><span class="token punctuation">,</span> <span class="token string single-quoted-string">&#39;&#39;</span><span class="token punctuation">,</span> <span class="token variable">$request</span><span class="token operator">-&gt;</span><span class="token property">headers</span><span class="token operator">-&gt;</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;referer&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

    <span class="token variable">$referer</span> <span class="token operator">=</span> <span class="token class-name static-context">Str</span><span class="token operator">::</span><span class="token function">replaceFirst</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;http://&#39;</span><span class="token punctuation">,</span> <span class="token string single-quoted-string">&#39;&#39;</span><span class="token punctuation">,</span> <span class="token variable">$referer</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

    <span class="token keyword">return</span> <span class="token class-name static-context">Str</span><span class="token operator">::</span><span class="token function">startsWith</span><span class="token punctuation">(</span><span class="token variable">$referer</span><span class="token punctuation">,</span> <span class="token function">config</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;sanctum.stateful&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token operator">||</span>
            <span class="token class-name">Str</span><span class="token operator">::</span><span class="token function">is</span><span class="token punctuation">(</span><span class="token function">config</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;sanctum.stateful&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token variable">$referer</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre></div><p>\xA1Est\xE1 comprobando el <code>Referrer</code>!</p><p>Por el momento en Postman, esto no est\xE1 bien configurado, as\xED que agr\xE9guelo a su lista de encabezados y env\xEDe la solicitud nuevamente.</p><p><img src="`+a+'" alt="Localhost port"></p><p>Y listo, una solicitud exitosa a un punto final autenticado.</p><p>Es mejor en este punto guardar su dominio en una variable de entorno en Postman. Si esto cambia y tiene muchos puntos finales, ser\xE1 una pesadilla actualizarlo.</p><p>Haga click en el engranaje en la parte superior derecha, seleccione su entorno y agregue manualmente su host.</p><p><img src="'+k+'" alt="Env name"></p><p>Una vez que haya guardado eso, cambie el valor del encabezado y env\xEDe la solicitud nuevamente.</p><p><img src="'+a+'" alt="Users list"></p><p>Todav\xEDa funciona. Excelente.</p><p>Deber\xE1 agregar el encabezado <code>Referrer</code> a todas las solicitudes que realice a su API, si est\xE1n protegidas con Sanctum. Sin embargo, eso no es demasiado problema.</p><h2 id="una-nota-rapida-sobre-otras-rutas-web" tabindex="-1">Una nota r\xE1pida sobre otras rutas web <a class="header-anchor" href="#una-nota-rapida-sobre-otras-rutas-web" aria-hidden="true">#</a></h2><p>Sanctum nos permite usar la ruta web normal <code>/login</code> para autenticarnos, pero eso no es todo. Tambi\xE9n podemos pulsar <code>/logout</code> para invalidar el valor de la cookie autenticada.</p><p>Para estas otras rutas web (tambi\xE9n protegidas por CSRF), debe asegurarse de que tambi\xE9n est\xE1 enviando el token. Aqu\xED hay un ejemplo r\xE1pido.</p><p><img src="'+g+'" alt="logout"></p><p>Mi solicitud para <code>/logout</code> fue exitosa porque estoy enviando el encabezado <code>X-XSRF-TOKEN</code>, al igual que lo hicimos para <code>/login</code>.</p>',62),b=[h];function f(_,q,S,y,P,j){return s(),n("div",null,b)}var C=e(v,[["render",f]]);export{A as __pageData,C as default};
